-- ============================================================
-- 결과 확인
-- ============================================================
select
  (select count(*) from businesses)  as 사업자,
  (select count(*) from channels)    as 채널,
  (select count(*) from warehouses)  as 창고,
  (select count(*) from partners)    as 거래처,
  (select count(*) from products)    as 상품,
  (select count(*) from inventory)   as 재고항목,
  (select count(*) from slips)       as 전표,
  (select count(*) from slip_items)  as 전표품목,
  (select count(*) from cash_book)   as 현금출납;
